import React from "react";
import { useParams } from "react-router-dom";

const products = [
  {
    id: 1,
    title: "MacBook Air",
    price: 45000,
    description:
      "Good condition laptop for coding, development and study work.",
    image:
      "https://images.unsplash.com/photo-1517336714739-489689fd1ca8?w=500",
  },
  {
    id: 2,
    title: "Engineering Books",
    price: 1200,
    description:
      "Complete first year engineering books set in good condition.",
    image:
      "https://images.unsplash.com/photo-1516979187457-637abb4f9353?w=500",
  },
  {
    id: 3,
    title: "Study Table",
    price: 2500,
    description:
      "Wooden study table perfect for hostel and room setup.",
    image:
      "https://images.unsplash.com/photo-1505693416388-ac5ce068fe85?w=500",
  },
];

function ProductDetails() {
  const { id } = useParams();

  const product = products.find(
    (item) => item.id === parseInt(id)
  );

  if (!product) {
    return <h1>Product Not Found</h1>;
  }

  return (
    <div
      style={{
        padding: "40px",
        backgroundColor: "#f3f4f6",
        minHeight: "100vh",
        fontFamily: "Arial",
      }}
    >
      <div
        style={{
          maxWidth: "1000px",
          margin: "auto",
          backgroundColor: "white",
          borderRadius: "12px",
          overflow: "hidden",
          display: "flex",
          gap: "30px",
          padding: "30px",
          boxShadow: "0 4px 15px rgba(0,0,0,0.1)",
        }}
      >
        <img
          src={product.image}
          alt={product.title}
          style={{
            width: "400px",
            borderRadius: "10px",
            objectFit: "cover",
          }}
        />

        <div>
          <h1>{product.title}</h1>

          <h2 style={{ color: "green" }}>
            ₹{product.price}
          </h2>

          <p
            style={{
              color: "#555",
              lineHeight: "1.8",
              fontSize: "18px",
            }}
          >
            {product.description}
          </p>

          <button
            style={{
              marginTop: "20px",
              backgroundColor: "#2563eb",
              color: "white",
              padding: "14px 25px",
              border: "none",
              borderRadius: "8px",
              cursor: "pointer",
              fontSize: "16px",
            }}
          >
            Contact Seller
          </button>
        </div>
      </div>
    </div>
  );
}

export default ProductDetails;
